import org.elasticsearch.search.suggest.phrase.PhraseSuggestion;
import org.springframework.stereotype.Service;

import javax.annotation.PostConstruct;
import java.io.IOException;
import java.util.*;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class ProductSearchService {

    private final RestHighLevelClient client;
    private final SearchQueryService searchQueryService;
    private ObjectMapper objectMapper;

    private static final String INDEX = ElasticsearchIndexService.PRODUCT_INDEX;

    @PostConstruct
    public void init() {
        objectMapper = new ObjectMapper();
        objectMapper.registerModule(new JavaTimeModule());
    }

    public ProductSearchResponse search(ProductSearchRequest searchRequest) throws IOException {
        long startTime = System.currentTimeMillis();

        SearchRequest request = new SearchRequest(INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        // Build query
        BoolQueryBuilder boolQuery = buildQuery(searchRequest);
        sourceBuilder.query(boolQuery);

        // Pagination
        sourceBuilder.from(searchRequest.getPage() * searchRequest.getSize());
        sourceBuilder.size(searchRequest.getSize());

        // Sorting
        addSorting(sourceBuilder, searchRequest);

        // Highlighting
        addHighlighting(sourceBuilder);

        // Aggregations (Facets)
        addAggregations(sourceBuilder);

        request.source(sourceBuilder);

        SearchResponse response = client.search(request, RequestOptions.DEFAULT);
        long responseTime = System.currentTimeMillis() - startTime;

        ProductSearchResponse searchResponse = parseSearchResponse(response, searchRequest, responseTime);

        // Log search query asynchronously
        try {
            searchQueryService.logSearchQuery(
                    searchRequest.getQuery(),
                    null, null,
                    searchRequest.getPage(),
                    searchRequest.getSize(),
                    searchResponse.getTotalHits(),
                    responseTime,
                    searchRequest.getSortBy(),
                    searchRequest.getSortOrder(),
                    buildFilterMap(searchRequest)
            );
        } catch (Exception e) {
            log.warn("Failed to log search query", e);
        }

        return searchResponse;
    }

    private BoolQueryBuilder buildQuery(ProductSearchRequest searchRequest) {
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        // Full-text search
        if (searchRequest.getQuery() != null && !searchRequest.getQuery().trim().isEmpty()) {
            String query = searchRequest.getQuery().trim();

            MultiMatchQueryBuilder multiMatch = QueryBuilders.multiMatchQuery(query)
                    .field("name", 3.0f)
                    .field("name.keyword", 5.0f)
                    .field("description", 1.0f)
                    .field("brand", 2.0f)
                    .field("category", 2.0f)
                    .field("tags", 1.5f)
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .fuzziness(Fuzziness.AUTO)
                    .minimumShouldMatch("75%");

            boolQuery.must(multiMatch);

            // Boost exact phrase matches
            MatchPhraseQueryBuilder phraseMatch = QueryBuilders.matchPhraseQuery("name", query)
                    .boost(5.0f);
            boolQuery.should(phraseMatch);
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        // Category filter
        if (searchRequest.getCategories() != null && !searchRequest.getCategories().isEmpty()) {
            BoolQueryBuilder categoryBool = QueryBuilders.boolQuery();
            for (String category : searchRequest.getCategories()) {
                categoryBool.should(QueryBuilders.termQuery("categories", category));
                categoryBool.should(QueryBuilders.termQuery("category.keyword", category));
            }
            categoryBool.minimumShouldMatch(1);
            boolQuery.filter(categoryBool);
        }

        // Brand filter
        if (searchRequest.getBrands() != null && !searchRequest.getBrands().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("brand.keyword", searchRequest.getBrands()));
        }

        // Color filter
        if (searchRequest.getColors() != null && !searchRequest.getColors().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("color", searchRequest.getColors()));
        }

        // Size filter
        if (searchRequest.getSizes() != null && !searchRequest.getSizes().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("size", searchRequest.getSizes()));
        }

        // Tags filter
        if (searchRequest.getTags() != null && !searchRequest.getTags().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("tags", searchRequest.getTags()));
        }

        // Price range filter
        if (searchRequest.getMinPrice() != null || searchRequest.getMaxPrice() != null) {
            RangeQueryBuilder priceRange = QueryBuilders.rangeQuery("price");
            if (searchRequest.getMinPrice() != null) {
                priceRange.gte(searchRequest.getMinPrice());
            }
            if (searchRequest.getMaxPrice() != null) {
                priceRange.lte(searchRequest.getMaxPrice());
            }
            boolQuery.filter(priceRange);
        }

        // Rating filter
        if (searchRequest.getMinRating() != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("rating").gte(searchRequest.getMinRating()));
        }

        // In stock filter
        if (searchRequest.getInStock() != null && searchRequest.getInStock()) {
            boolQuery.filter(QueryBuilders.termQuery("inStock", true));
        }

        // Seller filter
        if (searchRequest.getSeller() != null && !searchRequest.getSeller().isEmpty()) {
            boolQuery.filter(QueryBuilders.termQuery("seller.keyword", searchRequest.getSeller()));
        }

        // Boost in-stock products
        boolQuery.should(QueryBuilders.termQuery("inStock", true).boost(2.0f));

        // Boost higher-rated products
        boolQuery.should(QueryBuilders.rangeQuery("rating").gte(4.0).boost(1.5f));

        return boolQuery;
    }

    private void addSorting(SearchSourceBuilder sourceBuilder, ProductSearchRequest searchRequest) {
        SortOrder order = "asc".equalsIgnoreCase(searchRequest.getSortOrder()) ?
                SortOrder.ASC : SortOrder.DESC;

        switch (searchRequest.getSortBy().toLowerCase()) {
            case "price":
                sourceBuilder.sort(SortBuilders.fieldSort("price").order(order));
                break;
            case "price_asc":
                sourceBuilder.sort(SortBuilders.fieldSort("price").order(SortOrder.ASC));
                break;
            case "price_desc":
                sourceBuilder.sort(SortBuilders.fieldSort("price").order(SortOrder.DESC));
                break;
            case "rating":
                sourceBuilder.sort(SortBuilders.fieldSort("rating").order(SortOrder.DESC));
                break;
            case "newest":
                sourceBuilder.sort(SortBuilders.fieldSort("createdAt").order(SortOrder.DESC));
                break;
            case "name":
                sourceBuilder.sort(SortBuilders.fieldSort("name.keyword").order(order));
                break;
            case "popularity":
                sourceBuilder.sort(SortBuilders.fieldSort("reviewCount").order(SortOrder.DESC));
                break;
            case "relevance":
            default:
                sourceBuilder.sort(SortBuilders.scoreSort().order(SortOrder.DESC));
                break;
        }
    }

    private void addHighlighting(SearchSourceBuilder sourceBuilder) {
        HighlightBuilder highlightBuilder = new HighlightBuilder()
                .field(new HighlightBuilder.Field("name").numOfFragments(1))
                .field(new HighlightBuilder.Field("description").numOfFragments(2).fragmentSize(150))
                .preTags("<em>")
                .postTags("</em>");
        sourceBuilder.highlighter(highlightBuilder);
    }

    private void addAggregations(SearchSourceBuilder sourceBuilder) {
        // Category facet
        TermsAggregationBuilder categoryAgg = AggregationBuilders
                .terms("categories")
                .field("category.keyword")
                .size(50);
        sourceBuilder.aggregation(categoryAgg);

        // Brand facet
        TermsAggregationBuilder brandAgg = AggregationBuilders
                .terms("brands")
                .field("brand.keyword")
                .size(50);
        sourceBuilder.aggregation(brandAgg);

        // Color facet
        TermsAggregationBuilder colorAgg = AggregationBuilders
                .terms("colors")
                .field("color")
                .size(30);
        sourceBuilder.aggregation(colorAgg);

        // Size facet
        TermsAggregationBuilder sizeAgg = AggregationBuilders
                .terms("sizes")
                .field("size")
                .size(20);
        sourceBuilder.aggregation(sizeAgg);

        // Tags facet
        TermsAggregationBuilder tagsAgg = AggregationBuilders
                .terms("tags")
                .field("tags")
                .size(30);
        sourceBuilder.aggregation(tagsAgg);

        // Price range facet
        RangeAggregationBuilder priceRangeAgg = AggregationBuilders
                .range("price_ranges")
                .field("price")
                .addUnboundedTo("Under $25", 25)
                .addRange("$25 - $50", 25, 50)
                .addRange("$50 - $100", 50, 100)
                .addRange("$100 - $200", 100, 200)
                .addRange("$200 - $500", 200, 500)
                .addUnboundedFrom("$500+", 500);
        sourceBuilder.aggregation(priceRangeAgg);

        // Rating facet
        HistogramAggregationBuilder ratingAgg = AggregationBuilders
                .histogram("ratings")
                .field("rating")
                .interval(1)
                .minDocCount(0);
        sourceBuilder.aggregation(ratingAgg);

        // Seller facet
        TermsAggregationBuilder sellerAgg = AggregationBuilders
                .terms("sellers")
                .field("seller.keyword")
                .size(20);
        sourceBuilder.aggregation(sellerAgg);

        // Average price
        sourceBuilder.aggregation(AggregationBuilders.avg("avg_price").field("price"));

        // Average rating
        sourceBuilder.aggregation(AggregationBuilders.avg("avg_rating").field("rating"));
    }

    private ProductSearchResponse parseSearchResponse(SearchResponse response,
                                                       ProductSearchRequest searchRequest,
                                                       long responseTime) {
        List<Product> products = new ArrayList<>();

        for (SearchHit hit : response.getHits().getHits()) {
            Product product = objectMapper.convertValue(hit.getSourceAsMap(), Product.class);

            // Apply highlights
            Map<String, HighlightField> highlightFields = hit.getHighlightFields();
            if (highlightFields.containsKey("name")) {
                Text[] fragments = highlightFields.get("name").fragments();
                if (fragments.length > 0) {
                    product.setName(fragments[0].string());
                }
            }

            products.add(product);
        }

        long totalHits = response.getHits().getTotalHits().value;
        int totalPages = (int) Math.ceil((double) totalHits / searchRequest.getSize());

        // Parse facets
        Map<String, List<FacetEntry>> facets = parseFacets(response);

        return ProductSearchResponse.builder()
                .products(products)
                .totalHits(totalHits)
                .page(searchRequest.getPage())
                .size(searchRequest.getSize())
                .totalPages(totalPages)
                .responseTimeMs(responseTime)
                .facets(facets)
                .build();
    }

    private Map<String, List<FacetEntry>> parseFacets(SearchResponse response) {
        Map<String, List<FacetEntry>> facets = new LinkedHashMap<>();

        if (response.getAggregations() == null) return facets;

        // Parse terms aggregations
        String[] termsAggNames = {"categories", "brands", "colors", "sizes", "tags", "sellers"};
        for (String aggName : termsAggNames) {
            try {
                Terms terms = response.getAggregations().get(aggName);
                if (terms != null) {
                    List<FacetEntry> entries = terms.getBuckets().stream()
                            .map(bucket -> FacetEntry.builder()
                                    .key(bucket.getKeyAsString())
                                    .count(bucket.getDocCount())
                                    .build())
                            .collect(Collectors.toList());
                    facets.put(aggName, entries);
                }
            } catch (Exception e) {
                log.debug("Could not parse aggregation: {}", aggName);
            }
        }

        // Parse price ranges
        try {
            Range priceRanges = response.getAggregations().get("price_ranges");
            if (priceRanges != null) {
                List<FacetEntry> entries = priceRanges.getBuckets().stream()
                        .filter(bucket -> bucket.getDocCount() > 0)
                        .map(bucket -> FacetEntry.builder()
                                .key(bucket.getKeyAsString())
                                .count(bucket.getDocCount())
                                .build())
                        .collect(Collectors.toList());
                facets.put("price_ranges", entries);
            }
        } catch (Exception e) {
            log.debug("Could not parse price ranges aggregation");
        }

        // Parse rating histogram
        try {
            Histogram ratings = response.getAggregations().get("ratings");
            if (ratings != null) {
                List<FacetEntry> entries = ratings.getBuckets().stream()
                        .map(bucket -> FacetEntry.builder()
                                .key(String.valueOf((int) ((Histogram.Bucket) bucket).getKey()) + "+ stars")
                                .count(((Histogram.Bucket) bucket).getDocCount())
                                .build())
                        .collect(Collectors.toList());
                facets.put("ratings", entries);
            }
        } catch (Exception e) {
            log.debug("Could not parse ratings aggregation");
        }

        return facets;
    }

    public AutocompleteResponse autocomplete(String prefix) throws IOException {
        SearchRequest request = new SearchRequest(INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        // Completion suggestion
        SuggestBuilder suggestBuilder = new SuggestBuilder()
                .addSuggestion("product-suggest",
                        SuggestBuilders.completionSuggestion("name.suggest")
                                .prefix(prefix, Fuzziness.AUTO)
                                .size(10)
                                .skipDuplicates(true));

        sourceBuilder.suggest(suggestBuilder);
        sourceBuilder.size(0);
        request.source(sourceBuilder);

        SearchResponse response = client.search(request, RequestOptions.DEFAULT);

        List<String> suggestions = new ArrayList<>();
        if (response.getSuggest() != null) {
            CompletionSuggestion suggestion = response.getSuggest().getSuggestion("product-suggest");
            if (suggestion != null) {
                for (CompletionSuggestion.Entry entry : suggestion.getEntries()) {
                    for (CompletionSuggestion.Entry.Option option : entry.getOptions()) {
                        suggestions.add(option.getText().string());
                    }
                }
            }
        }

        // Also get popular queries matching the prefix
        List<String> popularQueries = searchQueryService.getPopularQueries(prefix, 5);

        return AutocompleteResponse.builder()
                .suggestions(suggestions)
                .popularQueries(popularQueries)
                .build();
    }

    public ProductSearchResponse searchSimilar(String productId, int size) throws IOException {
        long startTime = System.currentTimeMillis();

        Product product = new ProductIndexingService(client).getProduct(productId);
        if (product == null) {
            return ProductSearchResponse.builder()
                    .products(Collections.emptyList())
                    .totalHits(0)
                    .build();
        }

        SearchRequest request = new SearchRequest(INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        // Must not include the same product
        boolQuery.mustNot(QueryBuilders.termQuery("id", productId));

        // Should match same category
        if (product.getCategory() != null) {
            boolQuery.should(QueryBuilders.termQuery("category.keyword", product.getCategory()).boost(3.0f));
        }

        // Should match same brand
        if (product.getBrand() != null) {
            boolQuery.should(QueryBuilders.termQuery("brand.keyword", product.getBrand()).boost(2.0f));
        }

        // Should match similar price range (±30%)
        if (product.getPrice() != null) {
            double minPrice = product.getPrice().doubleValue() * 0.7;
            double maxPrice = product.getPrice().doubleValue() * 1.3;
            boolQuery.should(QueryBuilders.rangeQuery("price").gte(minPrice).lte(maxPrice).boost(1.5f));
        }

        // Should match similar tags
        if (product.getTags() != null && !product.getTags().isEmpty()) {
            boolQuery.should(QueryBuilders.termsQuery("tags", product.getTags()).boost(2.0f));
        }

        // More Like This on name and description
        String[] likeTexts = {product.getName()};
        if (product.getDescription() != null) {
            likeTexts = new String[]{product.getName(), product.getDescription()};
        }
        MoreLikeThisQueryBuilder mlt = QueryBuilders.moreLikeThisQuery(
                        new String[]{"name", "description"},
                        likeTexts,
                        null)
                .minTermFreq(1)
                .minDocFreq(1)
                .maxQueryTerms(12)
                .boost(2.0f);
        boolQuery.should(mlt);

        boolQuery.minimumShouldMatch(1);

        sourceBuilder.query(boolQuery);
        sourceBuilder.size(size);
        request.source(sourceBuilder);

        SearchResponse response = client.search(request, RequestOptions.DEFAULT);
        long responseTime = System.currentTimeMillis() - startTime;

        List<Product> products = new ArrayList<>();
        for (SearchHit hit : response.getHits().getHits()) {
            products.add(objectMapper.convertValue(hit.getSourceAsMap(), Product.class));
        }

        return ProductSearchResponse.builder()
                .products(products)
                .totalHits(response.getHits().getTotalHits().value)
                .responseTimeMs(responseTime)
                .build();
    }

    private Map<String, String> buildFilterMap(ProductSearchRequest request) {
        Map<String, String> filters = new HashMap<>();
        if (request.getCategories() != null && !request.getCategories().isEmpty()) {
            filters.put("categories", String.join(",", request.getCategories()));
        }
        if (request.getBrands() != null && !request.getBrands().isEmpty()) {
            filters.put("brands", String.join(",", request.getBrands()));
        }
        if (request.getMinPrice() != null) {
            filters.put("minPrice", request.getMinPrice().toString());
        }
        if (request.getMaxPrice() != null) {
            filters.put("maxPrice", request.getMaxPrice().toString());
        }
        if (request.getMinRating() != null) {
            filters.put("minRating", request.getMinRating().toString());
        }
        if (request.getInStock() != null) {
            filters.put("inStock", request.getInStock().toString());
        }
        return filters;
    }
}

