package com.ecommerce.search.service;

import com.ecommerce.search.model.SearchQuery;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortBuilders;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.stereotype.Service;

import javax.annotation.PostConstruct;
import java.io.IOException;
import java.time.LocalDateTime;
import java.util.*;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class SearchQueryService {

    private final RestHighLevelClient client;
    private ObjectMapper objectMapper;

    private static final String INDEX = ElasticsearchIndexService.SEARCH_QUERY_INDEX;

    @PostConstruct
    public void init() {
        objectMapper = new ObjectMapper();
        objectMapper.registerModule(new JavaTimeModule());
    }

    public void logSearchQuery(String queryText, String userId, String sessionId,
                                int page, int pageSize, long resultCount,
                                long responseTimeMs, String sortBy, String sortOrder,
                                Map<String, String> filters) {
        try {
            SearchQuery searchQuery = SearchQuery.builder()
                    .id(UUID.randomUUID().toString())
                    .queryText(queryText)
                    .userId(userId)
                    .sessionId(sessionId)
                    .page(page)
                    .pageSize(pageSize)
                    .resultCount((int) resultCount)
                    .responseTimeMs(responseTimeMs)
                    .sortBy(sortBy)
                    .sortOrder(sortOrder)
                    .filters(filters)
                    .timestamp(LocalDateTime.now())
                    .build();

            Map<String, Object> queryMap = objectMapper.convertValue(searchQuery, Map.class);

            IndexRequest request = new IndexRequest(INDEX)
                    .id(searchQuery.getId())
                    .source(queryMap, XContentType.JSON);

            IndexResponse response = client.index(request, RequestOptions.DEFAULT);
            log.debug("Search query logged: {}", response.getId());
        } catch (Exception e) {
            log.warn("Failed to log search query: {}", e.getMessage());
        }
    }

    public List<String> getPopularQueries(String prefix, int size) throws IOException {
        SearchRequest request = new SearchRequest(INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        if (prefix != null && !prefix.isEmpty()) {
            boolQuery.must(QueryBuilders.prefixQuery("queryText.keyword", prefix.toLowerCase()));
        }

        // Only recent queries (last 30 days)
        boolQuery.filter(QueryBuilders.rangeQuery("timestamp")
                .gte("now-30d/d"));

        sourceBuilder.query(boolQuery);
        sourceBuilder.size(0);

        sourceBuilder.aggregation(
                AggregationBuilders.terms("popular_queries")
                        .field("queryText.keyword")
                        .size(size)
                        .minDocCount(2)
        );

        request.source(sourceBuilder);
        SearchResponse response = client.search(request, RequestOptions.DEFAULT);

        List<String> popularQueries = new ArrayList<>();
        if (response.getAggregations() != null) {
            Terms terms = response.getAggregations().get("popular_queries");
            if (terms != null) {
                popularQueries = terms.getBuckets().stream()
                        .map(Terms.Bucket::getKeyAsString)
                        .collect(Collectors.toList());
            }
        }

        return popularQueries;
    }

    public List<SearchQuery> getRecentSearches(String userId, int size) throws IOException {
        SearchRequest request = new SearchRequest(INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        sourceBuilder.query(QueryBuilders.termQuery("userId", userId));
        sourceBuilder.sort(SortBuilders.fieldSort("timestamp").order(SortOrder.DESC));
        sourceBuilder.size(size);

        request.source(sourceBuilder);
        SearchResponse response = client.search(request, RequestOptions.DEFAULT);

        List<SearchQuery> queries = new ArrayList<>();
        for (var hit : response.getHits().getHits()) {
            queries.add(objectMapper.convertValue(hit.getSourceAsMap(), SearchQuery.class));
        }

        return queries;
    }

    public Map<String, Object> getSearchAnalytics(int days) throws IOException {
        SearchRequest request = new SearchRequest(INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        sourceBuilder.query(QueryBuilders.rangeQuery("timestamp")
                .gte("now-" + days + "d/d"));

        sourceBuilder.size(0);

        // Total search count
        sourceBuilder.aggregation(AggregationBuilders.count("total_searches").field("queryText.keyword"));

        // Top queries
        sourceBuilder.aggregation(AggregationBuilders.terms("top_queries")
                .field("queryText.keyword")
                .size(20));

        // Zero-result queries
        sourceBuilder.aggregation(AggregationBuilders.filter("zero_results",
                QueryBuilders.termQuery("resultCount", 0)));

        // Average response time
        sourceBuilder.aggregation(AggregationBuilders.avg("avg_response_time")
                .field("responseTimeMs"));

        request.source(sourceBuilder);
        SearchResponse response = client.search(request, RequestOptions.DEFAULT);

        Map<String, Object> analytics = new LinkedHashMap<>();
        analytics.put("totalSearches", response.getHits().getTotalHits().value);

        if (response.getAggregations() != null) {
            Terms topQueries = response.getAggregations().get("top_queries");
            if (topQueries != null) {
                List<Map<String, Object>> topQueryList = topQueries.getBuckets().stream()
                        .map(bucket -> {
                            Map<String, Object> entry = new HashMap<>();
                            entry.put("query", bucket.getKeyAsString());
                            entry.put("count", bucket.getDocCount());
                            return entry;
                        })
                        .collect(Collectors.toList());
                analytics.put("topQueries", topQueryList);
            }

            var avgResponseTime = (org.elasticsearch.search.aggregations.metrics.Avg)
                    response.getAggregations().get("avg_response_time");
            if (avgResponseTime != null) {
                analytics.put("avgResponseTimeMs", avgResponseTime.getValue());
            }
        }

        return analytics;
    }
}

