package com.ecommerce.search.controller;

import com.ecommerce.search.model.Product;
import com.ecommerce.search.service.ProductIndexingService;
import lombok.RequiredArgsConstructor;
import org.elasticsearch.action.bulk.BulkResponse;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/products")
@RequiredArgsConstructor
public class ProductController {

    private final ProductIndexingService productIndexingService;

    @PostMapping
    public ResponseEntity<Map<String, String>> indexProduct(@RequestBody Product product) throws IOException {
        String id = productIndexingService.indexProduct(product);
        Map<String, String> response = new HashMap<>();
        response.put("id", id);
        response.put("message", "Product indexed successfully");
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }

    @PostMapping("/bulk")
    public ResponseEntity<Map<String, Object>> bulkIndexProducts(@RequestBody List<Product> products) throws IOException {
        BulkResponse bulkResponse = productIndexingService.bulkIndexProducts(products);
        Map<String, Object> response = new HashMap<>();
        response.put("itemCount", products.size());
        response.put("hasFailures", bulkResponse.hasFailures());
        response.put("took", bulkResponse.getTook().getMillis() + "ms");
        if (bulkResponse.hasFailures()) {
            response.put("failureMessage", bulkResponse.buildFailureMessage());
        }
        return ResponseEntity.ok(response);
    }

    @GetMapping("/{id}")
    public ResponseEntity<Product> getProduct(@PathVariable String id) throws IOException {
        Product product = productIndexingService.getProduct(id);
        if (product == null) {
            return ResponseEntity.notFound().build();
        }
        return ResponseEntity.ok(product);
    }

    @PutMapping("/{id}")
    public ResponseEntity<Map<String, String>> updateProduct(@PathVariable String id,
                                                              @RequestBody Product product) throws IOException {
        String result = productIndexingService.updateProduct(id, product);
        Map<String, String> response = new HashMap<>();
        response.put("id", id);
        response.put("result", result);
        return ResponseEntity.ok(response);
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Map<String, String>> deleteProduct(@PathVariable String id) throws IOException {
        String result = productIndexingService.deleteProduct(id);
        Map<String, String> response = new HashMap<>();
        response.put("id", id);
        response.put("result", result);
        return ResponseEntity.ok(response);
    }

    @DeleteMapping("/bulk")
    public ResponseEntity<Map<String, Object>> bulkDeleteProducts(@RequestBody List<String> ids) throws IOException {
        BulkResponse bulkResponse = productIndexingService.bulkDeleteProducts(ids);
        Map<String, Object> response = new HashMap<>();
        response.put("deletedCount", ids.size());
        response.put("hasFailures", bulkResponse.hasFailures());
        return ResponseEntity.ok(response);
    }
}

