package com.ecommerce.search.controller;

import com.ecommerce.search.dto.AutocompleteResponse;
import com.ecommerce.search.dto.ProductSearchRequest;
import com.ecommerce.search.dto.ProductSearchResponse;
import com.ecommerce.search.model.SearchQuery;
import com.ecommerce.search.service.ProductSearchService;
import com.ecommerce.search.service.SearchQueryService;
import lombok.RequiredArgsConstructor;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.math.BigDecimal;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/search")
@RequiredArgsConstructor
public class SearchController {

    private final ProductSearchService productSearchService;
    private final SearchQueryService searchQueryService;

    @PostMapping
    public ResponseEntity<ProductSearchResponse> search(@RequestBody ProductSearchRequest request) throws IOException {
        ProductSearchResponse response = productSearchService.search(request);
        return ResponseEntity.ok(response);
    }

    @GetMapping
    public ResponseEntity<ProductSearchResponse> searchGet(
            @RequestParam(required = false) String q,
            @RequestParam(required = false) List<String> categories,
            @RequestParam(required = false) List<String> brands,
            @RequestParam(required = false) List<String> colors,
            @RequestParam(required = false) List<String> sizes,
            @RequestParam(required = false) List<String> tags,
            @RequestParam(required = false) BigDecimal minPrice,
            @RequestParam(required = false) BigDecimal maxPrice,
            @RequestParam(required = false) Double minRating,
            @RequestParam(required = false) Boolean inStock,
            @RequestParam(required = false) String seller,
            @RequestParam(defaultValue = "relevance") String sortBy,
            @RequestParam(defaultValue = "desc") String sortOrder,
            @RequestParam(defaultValue = "0") int page,
            @RequestParam(defaultValue = "20") int size) throws IOException {

        ProductSearchRequest request = ProductSearchRequest.builder()
                .query(q)
                .categories(categories)
                .brands(brands)
                .colors(colors)
                .sizes(sizes)
                .tags(tags)
                .minPrice(minPrice)
                .maxPrice(maxPrice)
                .minRating(minRating)
                .inStock(inStock)
                .seller(seller)
                .sortBy(sortBy)
                .sortOrder(sortOrder)
                .page(page)
                .size(size)
                .build();

        ProductSearchResponse response = productSearchService.search(request);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/autocomplete")
    public ResponseEntity<AutocompleteResponse> autocomplete(@RequestParam String prefix) throws IOException {
        AutocompleteResponse response = productSearchService.autocomplete(prefix);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/similar/{productId}")
    public ResponseEntity<ProductSearchResponse> findSimilar(
            @PathVariable String productId,
            @RequestParam(defaultValue = "10") int size) throws IOException {
        ProductSearchResponse response = productSearchService.searchSimilar(productId, size);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/popular")
    public ResponseEntity<List<String>> getPopularQueries(
            @RequestParam(required = false) String prefix,
            @RequestParam(defaultValue = "10") int size) throws IOException {
        List<String> queries = searchQueryService.getPopularQueries(prefix, size);
        return ResponseEntity.ok(queries);
    }

    @GetMapping("/history/{userId}")
    public ResponseEntity<List<SearchQuery>> getSearchHistory(
            @PathVariable String userId,
            @RequestParam(defaultValue = "20") int size) throws IOException {
        List<SearchQuery> history = searchQueryService.getRecentSearches(userId, size);
        return ResponseEntity.ok(history);
    }

    @GetMapping("/analytics")
    public ResponseEntity<Map<String, Object>> getAnalytics(
            @RequestParam(defaultValue = "30") int days) throws IOException {
        Map<String, Object> analytics = searchQueryService.getSearchAnalytics(days);
        return ResponseEntity.ok(analytics);
    }
}

