package com.ecommerce.search.controller;

import com.ecommerce.search.service.ElasticsearchIndexService;
import lombok.RequiredArgsConstructor;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api/admin/indices")
@RequiredArgsConstructor
public class IndexManagementController {

    private final ElasticsearchIndexService indexService;

    @PostMapping("/products/recreate")
    public ResponseEntity<Map<String, String>> recreateProductIndex() throws IOException {
        indexService.recreateProductIndex();
        Map<String, String> response = new HashMap<>();
        response.put("message", "Product index recreated successfully");
        return ResponseEntity.ok(response);
    }

    @GetMapping("/{indexName}/exists")
    public ResponseEntity<Map<String, Object>> checkIndex(@PathVariable String indexName) throws IOException {
        boolean exists = indexService.indexExists(indexName);
        Map<String, Object> response = new HashMap<>();
        response.put("index", indexName);
        response.put("exists", exists);
        return ResponseEntity.ok(response);
    }

    @DeleteMapping("/{indexName}")
    public ResponseEntity<Map<String, String>> deleteIndex(@PathVariable String indexName) throws IOException {
        indexService.deleteIndex(indexName);
        Map<String, String> response = new HashMap<>();
        response.put("message", "Index " + indexName + " deleted");
        return ResponseEntity.ok(response);
    }
}

